'use client'

import { useState } from "react"
import { InventoryItem } from "@/types/inventory"
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card"
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs"
import { Button } from "@/components/ui/button"
import { Package, Truck, Import, Plus, AlertTriangle, Search, Filter } from "lucide-react"
import { Input } from "@/components/ui/input"
import { Badge } from "@/components/ui/badge"
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table"
import { formatCurrency } from "@/lib/utils"

interface InventoryClientProps {
    initialItems: InventoryItem[];
}

export default function InventoryClient({ initialItems }: InventoryClientProps) {
    const [searchTerm, setSearchTerm] = useState("")

    const filteredItems = initialItems.filter(item =>
        item.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
        item.category.toLowerCase().includes(searchTerm.toLowerCase())
    )

    const lowStockCount = initialItems.filter(i => (i.total_quantity || 0) <= i.min_stock).length
    const totalValue = initialItems.reduce((acc, item) => acc + ((item.total_quantity || 0) * (item.sell_price || 0)), 0)

    return (
        <div className="space-y-6">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div>
                    <h1 className="text-2xl font-bold text-foreground flex items-center gap-2">
                        <Package className="h-7 w-7 text-primary" />
                        Gestão de Estoque
                    </h1>
                    <p className="text-muted-foreground">
                        Controle de produtos, lotes e fornecedores
                    </p>
                </div>
                <div className="flex gap-2">
                    <Button>
                        <Plus className="mr-2 h-4 w-4" /> Novo Produto
                    </Button>
                </div>
            </div>

            <div className="grid gap-4 md:grid-cols-3">
                <Card>
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-sm font-medium">Total de Produtos</CardTitle>
                        <Package className="h-4 w-4 text-muted-foreground" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold">{initialItems.length}</div>
                    </CardContent>
                </Card>
                <Card>
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-sm font-medium">Estoque Baixo</CardTitle>
                        <AlertTriangle className="h-4 w-4 text-amber-500" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold text-amber-500">{lowStockCount}</div>
                    </CardContent>
                </Card>
                <Card>
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-sm font-medium">Valor Estimado</CardTitle>
                        <div className="text-xs text-muted-foreground">Preço Venda</div>
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold text-green-600">{formatCurrency(totalValue)}</div>
                    </CardContent>
                </Card>
            </div>

            <Tabs defaultValue="products" className="space-y-4">
                <TabsList>
                    <TabsTrigger value="products">
                        <Package className="w-4 h-4 mr-2" /> Produtos
                    </TabsTrigger>
                    <TabsTrigger value="inbound">
                        <Import className="w-4 h-4 mr-2" /> Entradas
                    </TabsTrigger>
                    <TabsTrigger value="suppliers">
                        <Truck className="w-4 h-4 mr-2" /> Fornecedores
                    </TabsTrigger>
                </TabsList>

                <TabsContent value="products" className="space-y-4">
                    <div className="flex gap-2 mb-4">
                        <div className="relative flex-1 max-w-sm">
                            <Search className="absolute left-2.5 top-2.5 h-4 w-4 text-muted-foreground" />
                            <Input
                                placeholder="Buscar produtos..."
                                value={searchTerm}
                                onChange={(e) => setSearchTerm(e.target.value)}
                                className="pl-8"
                            />
                        </div>
                    </div>

                    <div className="rounded-md border bg-card">
                        <Table>
                            <TableHeader>
                                <TableRow>
                                    <TableHead>Nome</TableHead>
                                    <TableHead>Categoria</TableHead>
                                    <TableHead>Saldo Atual</TableHead>
                                    <TableHead>Preço Venda</TableHead>
                                    <TableHead>Status</TableHead>
                                    <TableHead className="w-[80px]">Ações</TableHead>
                                </TableRow>
                            </TableHeader>
                            <TableBody>
                                {filteredItems.length === 0 ? (
                                    <TableRow>
                                        <TableCell colSpan={6} className="text-center py-8 text-muted-foreground">
                                            Nenhum produto encontrado
                                        </TableCell>
                                    </TableRow>
                                ) : (
                                    filteredItems.map(item => (
                                        <TableRow key={item.id}>
                                            <TableCell className="font-medium">{item.name}</TableCell>
                                            <TableCell>
                                                <Badge variant="outline">{item.category}</Badge>
                                            </TableCell>
                                            <TableCell>
                                                {item.total_quantity} {item.unit}
                                            </TableCell>
                                            <TableCell>
                                                {item.sell_price ? formatCurrency(item.sell_price) : '-'}
                                            </TableCell>
                                            <TableCell>
                                                {(item.total_quantity || 0) <= item.min_stock ? (
                                                    <Badge variant="destructive" className="gap-1">
                                                        <AlertTriangle className="h-3 w-3" /> Baixo
                                                    </Badge>
                                                ) : (
                                                    <Badge variant="outline" className="text-green-600 border-green-200 bg-green-50">Normal</Badge>
                                                )}
                                            </TableCell>
                                            <TableCell>
                                                {/* Actions dropdown placeholder */}
                                                <Button variant="ghost" size="sm">Editar</Button>
                                            </TableCell>
                                        </TableRow>
                                    ))
                                )}
                            </TableBody>
                        </Table>
                    </div>
                </TabsContent>

                <TabsContent value="inbound">
                    <Card>
                        <CardContent className="p-8 text-center text-muted-foreground">
                            Módulo de entrada de notas em desenvolvimento.
                        </CardContent>
                    </Card>
                </TabsContent>

                <TabsContent value="suppliers">
                    <Card>
                        <CardContent className="p-8 text-center text-muted-foreground">
                            Gestão de fornecedores em desenvolvimento.
                        </CardContent>
                    </Card>
                </TabsContent>
            </Tabs>
        </div>
    );
}
